
.inf-dialog__header {
  display: flex;
  align-items: flex-start;
  gap: 0.875rem;
  margin-bottom: 0.875rem;
}

.inf-dialog__icon-wrap {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 44px;
  height: 44px;
  border-radius: var(--inf-radius-sm);
  flex-shrink: 0;

  &--info {
    color: var(--inf-info);
    background: color-mix(in srgb, var(--inf-info) 12%, transparent);
  }
}

.inf-dialog__title {
  margin: 0.15rem 0 0;
  font-size: 1.35rem;
  line-height: 1.2;
}

.inf-dialog__message {
  margin: 0 0 1.35rem;
  font-size: 0.9375rem;
  line-height: 1.65;
  color: var(--inf-text-secondary);
}

.inf-dialog__footer {
  display: flex;
  justify-content: flex-end;
}
