
.inf-status-rail {
  display: flex;
  flex-direction: column;
  min-height: 0;
  height: 100%;
  padding: 0.875rem clamp(0.75rem, 1.5vw, 1rem);
  overflow-y: auto;
  overscroll-behavior: contain;
}

.inf-status-rail__stream {
  display: flex;
  flex-direction: column;
  min-height: 0;
}

.inf-status-rail__empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.5rem;
  padding: 2rem 0.5rem;
  text-align: center;
}

.inf-status-rail__empty-icon {
  color: var(--inf-text-muted);
  opacity: 0.6;
}
